#include <vector>
#include <algorithm>
int max_subarray(const std::vector<int>& nums) {
    int max_sum = nums[0], cur = nums[0];
    for (int i = 1; i < (int)nums.size(); i++) {
        cur = std::max(nums[i], cur + nums[i]);
        max_sum = std::max(max_sum, cur);
    }
    return max_sum;
}

